  VALUES
  ('households_surveyed', 'households_surveyed', 'demographics_registration', 'Number of households surveyed', 'count', 'neutral', 'none', 'households', 'ok', 1.0, NULL, NULL, NULL, NULL, 'neutral survey-design metric; no need trigger. If a sample-size reliability cut is needed, flag bottom national quartile (lowest counts) as low-power districts.'),
  ('women_15_49_interviewed', 'women_15_49_interviewed', 'demographics_registration', 'Women age 15-49 interviewed', 'count', 'neutral', 'none', 'women_15_49', 'ok', 1.0, NULL, NULL, NULL, NULL, 'neutral survey-design metric; no need trigger. For reliability weighting, bottom national quartile (lowest counts) indicates lower statistical power for women-based indicators.'),
