  ('female_ever_schooled_pct', 'female_population_age_6_years_and_above_ever_schooled_pct', 'demographics_registration', 'Females age 6+ who ever attended school (%)', 'pct', 'higher_is_better', 'female_education', 'women_15_49', 'ok', 1.0, '<=', 55.0, 70.0, 'SDG4 universal schooling', 'lowest national quartile (lowest % ever schooled) = worst-need districts for female education.'),
